// ─────────────────────────────────────────────
// VHSYS :: nf_service_info
// Rota   : POST /nf_service_info
// ─────────────────────────────────────────────
// A extensão (getServiceNFInfo.ts) envia:
//   body: JSON.stringify({ xml_ref: decodedText })
// O Flask: data.get('xml_ref', '') → se vazio → 400
// ─────────────────────────────────────────────

const input = $input.first().json;
const body = (input.body !== undefined) ? input.body : input;
const xml_string = (body.xml_ref !== undefined) ? String(body.xml_ref) : '';

if (!xml_string.trim()) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'No XML data provided' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'input_validated',
  xml_length: xml_string.length,
  level: 'info'
}));

return { _valid: true, xml_string };

// ─────────────────────────────────────────────
// Parse XML + Transform
// ─────────────────────────────────────────────
// Espelha exatamente get_nf_service_info() do Flask:
//   xmltodict.parse → xml_dict['xjx']['cmd']
//   @t = nome do campo, #text = valor
//   clean_cell() em cada valor
//   del 'no-set', 'estoque_pedido', 'bloquear_edicao_cliente'
//   cc_ref = CC_MANAGER.get_cc_label(obs_interno_pedido)
// ─────────────────────────────────────────────

const ctx = $input.first().json;
const xml_string = ctx.xml_string;

// ── clean_cell() — espelha Flask ──
function cleanCell(value) {
  if (typeof value !== 'string') return value;
  let cleaned = value.replace(/\\n|\\t|\\r|\n|\t|\r/g, ' ');
  cleaned = cleaned.replace(/\s+/g, ' ').trim();
  return cleaned;
}

// ── get_cc_label() — ordem IDÊNTICA ao Flask (cost_center_manager.py) ──
// Flask: extract_cc_value → extract_numeric_part → extract_prefix
//        → extract_cc_text_value → extract_cc_text_value_exceptions
function getCCLabel(text) {
  if (!text) return '-1';
  const s = String(text);
  // Exceções fixas (método da instância)
  if (s === 'RT - Vendas') return 'Vendas';
  if (s === 'Marketing') return 'Marketing';
  if (s === 'Vendas') return s;
  if (s === 'Administração') return s;
  // Nível 1: extract_cc_value → CC[-\s]*(\d+)
  let m = s.match(/CC[-\s]*(\d+)/i);
  if (m) return m[1];
  // Nível 2: extract_numeric_part → \b(\d{6})\b
  m = s.match(/\b(\d{6})\b/);
  if (m) return m[1];
  // Nível 3: extract_prefix → ^[A-Z]{2}-[A-Z0-9]{3}
  m = s.match(/^[A-Z]{2}-[A-Z0-9]{3}/);
  if (m) return m[0];
  // Nível 4: extract_cc_text_value → CC- + 6 chars
  let idx = s.indexOf('CC-');
  if (idx !== -1) return s.substr(idx + 3, 6);
  // Nível 5: extract_cc_text_value_exceptions → remove '/' e repete
  const noSlash = s.replace(/\//g, '');
  idx = noSlash.indexOf('CC-');
  if (idx !== -1) {
    const end = noSlash.indexOf('/', idx);
    if (end === -1) return noSlash.substr(idx + 3, 6);
    return noSlash.substring(idx + 3, end);
  }
  return '-1';
}

// ── Parse XML (equivale a xmltodict.parse) ──
// Extrai cada <cmd ... t="campo" ...>valor</cmd>
function parseXjxXml(xml) {
  const info = {};
  const cmdRegex = /<cmd[^>]+t="([^"]*?)"[^>]*>([\s\S]*?)<\/cmd>/g;
  let match;
  while ((match = cmdRegex.exec(xml)) !== null) {
    const fieldName = match[1];
    let value = match[2].replace(/<\!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').trim();
    info[fieldName] = cleanCell(value);
  }
  return info;
}

let info_dict_ref;
try {
  info_dict_ref = parseXjxXml(xml_string);
} catch (e) {
  return [{ json: { _error: true, message: 'Failed to parse XML: ' + String(e.message) } }];
}

// Espelha: del info_dict_ref['no-set'] / 'estoque_pedido' / 'bloquear_edicao_cliente'
delete info_dict_ref['no-set'];
delete info_dict_ref['estoque_pedido'];
delete info_dict_ref['bloquear_edicao_cliente'];

// id_servico é a PK — vem do XML
const id_servico = String(info_dict_ref.id_servico || '').trim();
if (!id_servico) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'nf_service_info',
    event: 'missing_id_servico',
    available_keys: Object.keys(info_dict_ref),
    level: 'warn'
  }));
  return [{ json: { _error: true, message: 'Missing id_servico in XML' } }];
}

// cc_ref via get_cc_label(obs_interno_pedido)
const cc_ref = getCCLabel(info_dict_ref.obs_interno_pedido || '');

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'xml_parsed',
  id_servico,
  cc_ref,
  fields_count: Object.keys(info_dict_ref).length,
  level: 'info'
}));

return [{
  json: {
    id_servico,
    obs_interno_pedido:          info_dict_ref.obs_interno_pedido          ?? null,
    obs_pedido:                  info_dict_ref.obs_pedido                  ?? null,
    numero_processo:             info_dict_ref.numero_processo             ?? null,
    condicao_pagamento:          info_dict_ref.condicao_pagamento          ?? null,
    condicao_pagamento_id:       info_dict_ref.condicao_pagamento_id       ?? null,
    valor_iss:                   info_dict_ref.valor_iss                   ?? null,
    aliq_iss:                    info_dict_ref.aliq_iss                    ?? null,
    valor_ir:                    info_dict_ref.valor_ir                    ?? null,
    aliq_ir:                     info_dict_ref.aliq_ir                     ?? null,
    valor_contribuicao:          info_dict_ref.valor_contribuicao          ?? null,
    aliq_contribuicao:           info_dict_ref.aliq_contribuicao           ?? null,
    valor_pis:                   info_dict_ref.valor_pis                   ?? null,
    aliq_pis:                    info_dict_ref.aliq_pis                    ?? null,
    valor_cofins:                info_dict_ref.valor_cofins                ?? null,
    aliq_cofins:                 info_dict_ref.aliq_cofins                 ?? null,
    valor_material:              info_dict_ref.valor_material              ?? null,
    valor_tributos_mun:          info_dict_ref.valor_tributos_mun          ?? null,
    valor_aliq_tributos_mun:     info_dict_ref.valor_aliq_tributos_mun     ?? null,
    valor_tributos:              info_dict_ref.valor_tributos              ?? null,
    valor_aliq_tributos:         info_dict_ref.valor_aliq_tributos         ?? null,
    valor_imposto:               info_dict_ref.valor_imposto               ?? null,
    valor_aliquota:              info_dict_ref.valor_aliquota              ?? null,
    valor_base_calculo:          info_dict_ref.valor_base_calculo          ?? null,
    valor_condicionado:          info_dict_ref.valor_condicionado          ?? null,
    valor_incondicionado:        info_dict_ref.valor_incondicionado        ?? null,
    valor_deducoes:              info_dict_ref.valor_deducoes              ?? null,
    itemLista_servico:           info_dict_ref.itemLista_servico           ?? null,
    valor_total_nota:            info_dict_ref.valor_total_nota            ?? null,
    valor_total_servicos:        info_dict_ref.valor_total_servicos        ?? null,
    desc_servicos:               info_dict_ref.desc_servicos               ?? null,
    serie_nota:                  info_dict_ref.serie_nota                  ?? null,
    id_pedido:                   info_dict_ref.id_pedido                   ?? null,
    vendedor_pedido_id:          info_dict_ref.vendedor_pedido_id          ?? null,
    vendedor_pedido:             info_dict_ref.vendedor_pedido             ?? null,
    ultrapassar_limite_credito:  info_dict_ref.ultrapassar_limite_credito  ?? null,
    contas_pedido:               info_dict_ref.contas_pedido               ?? null,
    id_cliente:                  info_dict_ref.id_cliente                  ?? null,
    nome_cliente:                info_dict_ref.nome_cliente                ?? null,
    cc_ref
  }
}];

// ── Sucesso ──
// Flask retorna HTTP 200 (não 201)
const row = $input.first().json;
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'upsert_complete',
  id_servico: row.id_servico,
  level: 'info'
}));
return {
  statusCode: 200,
  body: { message: 'Data extracted, cleaned, and converted to DataFrame successfully' }
};

// ── XML inválido ou sem id_servico ──
// Retorna 200 para não bloquear o loop da extensão
const input = $input.first().json;
const msg = input.message || 'No valid record found in XML';
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'empty_or_parse_error',
  detail: msg,
  level: 'warn'
}));
return {
  statusCode: 200,
  body: { message: 'Data extracted, cleaned, and converted to DataFrame successfully' }
};

// ── Erro de validação (sem xml_ref) ──
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// ── Erro de banco durante o UPSERT ──
const errData = $input.first().json;
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));
return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update service info' }
};
